    contexto:         lead.contexto || '',
    origen:           lead.origen || 'chatbot',
    estado:           'ERROR',
    error_detalle:    errorDetalle,
    respuesta_api:    null
  }
}];

const prep = $('Extraer Datos Entrada1').first().json;
const sessionId = prep.sessionId;
const clientId = prep.clientId || prep.client_id || '';
const companyName = prep.companyName || prep.company_name || 'la empresa';
const logData = $('Preparar Log OK').first().json || {};

const leadNombre = logData.nombre           || 'Desconocido';
const leadEmail  = logData.email            || '';
const leadTel    = logData.telefono         || '';
const leadProd   = logData.producto_interes || 'General';
const leadCtx    = logData.contexto         || '';

return [{ json: { sessionId, clientId, client_id: clientId, companyName, company_name: companyName, leadNombre, leadEmail, leadTel, leadProd, leadCtx } }];

const prepData = $('Preparar Datos Transcript1').first().json;
const clientId = prepData.clientId || prepData.client_id || '';
const companyName = prepData.companyName || prepData.company_name || 'la empresa';
const leadNombre = prepData.leadNombre;
const leadEmail  = prepData.leadEmail;
const leadTel    = prepData.leadTel;
const leadProd   = prepData.leadProd;
const leadCtx    = prepData.leadCtx;

const items = $input.all();
const historia = items.map(item => item.json).filter(m => m.role && m.content);

const now          = new Date();
const timestamp    = now.toISOString();
const fechaLegible = now.toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });
const fileTimestamp = timestamp.replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);

function esc(str) {
  return String(str || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/\n/g, '<br>');
}

const mensajesHtml = historia.length
  ? historia.map(msg => {
      const isUser  = msg.role === 'user';
      const label   = isUser ? '👤 Usuario' : '🤖 Asistente';
      const bgColor = isUser ? '#EEF2FF' : '#F0FDF4';
      const border  = isUser ? '#818CF8' : '#4ADE80';
      const labelClr = isUser ? '#3730A3' : '#166534';
      const hora    = msg.created_at
        ? new Date(msg.created_at).toLocaleTimeString('es-ES', { timeZone: 'Europe/Madrid', hour: '2-digit', minute: '2-digit' })
        : '';
      return `
  <div style="margin-bottom:14px;padding:14px 18px;background:${bgColor};border-left:4px solid ${border};border-radius:0 8px 8px 0;">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
      <span style="font-size:11px;font-weight:700;color:${labelClr};text-transform:uppercase;letter-spacing:.05em;">${label}</span>
      ${hora ? `<span style="font-size:11px;color:#9CA3AF;">${hora}</span>` : ''}
    </div>
    <div style="font-size:14px;line-height:1.7;color:#1F2937;">${esc(msg.content)}</div>
  </div>`;
    }).join('')
  : '<p style="color:#6B7280;font-style:italic;">No hay mensajes en el historial.</p>';

const fichaLead = `
  <div style="margin-top:28px;padding:18px 20px;background:#FFF7ED;border:1px solid #FED7AA;border-radius:8px;">
    <div style="font-size:11px;font-weight:700;color:#92400E;text-transform:uppercase;letter-spacing:.06em;margin-bottom:14px;">📋 Datos del lead capturado</div>
    <table style="width:100%;border-collapse:collapse;font-size:13px;">
      <tr><td style="padding:5px 12px 5px 0;color:#6B7280;width:130px;">Nombre</td><td style="padding:5px 0;color:#111827;font-weight:500;">${esc(leadNombre)}</td></tr>
      <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Email</td><td style="padding:5px 0;color:#111827;">${esc(leadEmail)}</td></tr>
      <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Teléfono</td><td style="padding:5px 0;color:#111827;">${esc(leadTel)}</td></tr>
      <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Producto</td><td style="padding:5px 0;color:#111827;">${esc(leadProd)}</td></tr>
      ${leadCtx ? `<tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Contexto</td><td style="padding:5px 0;color:#111827;">${esc(leadCtx)}</td></tr>` : ''}
    </table>
  </div>`;

const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1.0">
  <title>Transcript – Aicor Chatbot</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:#F9FAFB;color:#111827;padding:32px 16px}
    .wrap{max-width:780px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 1px 4px rgba(0,0,0,.12);overflow:hidden}
    .hdr{background:linear-gradient(135deg,#1E40AF,#2563EB);color:#fff;padding:28px 32px}
    .hdr h1{font-size:20px;font-weight:600;margin-bottom:8px}
    .hdr p{font-size:13px;opacity:.85;line-height:1.8;margin:0}
    .body{padding:28px 32px}
    .sec{font-size:11px;font-weight:700;color:#6B7280;text-transform:uppercase;letter-spacing:.08em;margin-bottom:16px;padding-bottom:8px;border-bottom:1px solid #E5E7EB}
    .foot{background:#F3F4F6;padding:14px 32px;font-size:11px;color:#9CA3AF;border-top:1px solid #E5E7EB}
  </style>
</head>
<body>
  <div class="wrap">
    <div class="hdr">
      <h1>📋 Transcript de conversación</h1>
      <p>
        🕐 ${fechaLegible}<br>
        👤 Lead: ${esc(leadNombre)}${leadEmail ? ' &lt;' + esc(leadEmail) + '&gt;' : ''}<br>
        📨 Total mensajes: ${historia.length}
      </p>
    </div>
    <div class="body">
      <div class="sec">Conversación completa</div>
      ${mensajesHtml}
      ${fichaLead}
    </div>
    <div class="foot">Generado automáticamente por Aicor Chatbot &middot; ${timestamp}</div>
  </div>
</body>
</html>`;

return [{
  json: {
    html_content:  html,
    file_name:     `transcript_${fileTimestamp}.html`,
    client_id:     clientId,
    company_name:  companyName,
    lead_nombre:   leadNombre,
    lead_email:    leadEmail,
    created_at:    timestamp,
    message_count: historia.length,
    storage_path:  `chatbot/${clientId}/transcript_${fileTimestamp}.html`
  }
}];

const uploadResponse = $json;
const prevData = $('Generate HTML Transcript').first().json;
const storagePath = prevData.storage_path;
const publicUrl   = `https://uovfdghgbanhjojtobtz.supabase.co/storage/v1/object/public/transcripts/${storagePath}`;
const uploadOk    = uploadResponse.statusCode >= 200 && uploadResponse.statusCode < 300;

return [{
  json: {
    client_id:       prevData.client_id,
    file_url:        uploadOk ? publicUrl : null,
    storage_path:    storagePath,
    file_name:       prevData.file_name,
    lead_nombre:     prevData.lead_nombre,
    lead_email:      prevData.lead_email,
    message_count:   prevData.message_count,
    created_at:      prevData.created_at,
    upload_status:   uploadOk ? 'OK' : 'ERROR',
    upload_response: JSON.stringify(uploadResponse)
  }
}];

