const clientId = $json.clientId || $json.client_id || '';
const companyName = $json.companyName || $json.company_name || 'la empresa';
const sessionId = $json.sessionId || (clientId + ':' + ($execution?.id || 'default'));
const userMsg   = ($json.userMsg || '').trim();
const msgLower  = userMsg.toLowerCase();

const BANNED_DOMAINS = [
  'bit.ly', 'tinyurl.com', 'cutt.ly', 'shorturl.at',
  'ow.ly', 't.co', 'rebrand.ly', 'bl.ink',
  'onlyfans.com', 'xvideos.com', 'pornhub.com',
  'casino', 'bet365', 'betfair',
  'phishing-site.com'
];

const BLOCKED_PATTERNS = [
  /\b(puta|puto|coño|hostia|gilipollas|imbécil|idiota|estupido|subnormal|retrasado|mongolo|maricón|zorra|perra|bastardo|cabrón|hdp|hijo de puta|mierda de empresa|asco de empresa)\b/i,
  /\b(te voy a|os voy a|voy a|te vas a|os vais a).{0,30}(matar|pegar|hundir|denunciar|destruir|arruinar|reventar|joder)\b/i,
  /\b(amenaza|amenazas|te arrepentirás|me las pagarás|ya verás|os arrepentiréis)\b/i,
  /\b(buy now|click here|free money|earn (fast|easy|quick)|guaranteed income|work from home|make money fast|crypto investment|double your|100% profit|exclusive offer|limited time offer|act now)\b/i,
  /\b(viagra|cialis|levitra|casino|jackpot|slot machine|free spin|win big|lottery winner|you have been selected)\b/i,
  /\b(ignore (previous|all|your) (instructions?|rules?|prompt)|forget (your|the) (instructions?|rules?|context)|act as (dan|jailbreak|unrestricted|evil)|pretend (you are|to be) (without|no) (restrictions?|limits?|rules?))\b/i,
  /https?:\/\/[^\s]{60,}/i,
  /\b(\d{1,3}\.){3}\d{1,3}\b/
];

const urlsEnMensaje = msgLower.match(/https?:\/\/[^\s]+|www\.[^\s]+|[a-z0-9.-]+\.(com|es|net|org|io|co|info|biz|xyz|top|club|site|online|shop|store)[^\s]*/gi) || [];
const dominiosBloqueados = urlsEnMensaje.some(url => BANNED_DOMAINS.some(domain => url.includes(domain)));
const msgDemasiadoLargo = userMsg.length > 800;

let bloqueado = false;
let motivoBloqueo = '';

if (dominiosBloqueados) { bloqueado = true; motivoBloqueo = 'dominio_baneado'; }
else if (BLOCKED_PATTERNS.some(p => p.test(userMsg))) { bloqueado = true; motivoBloqueo = 'contenido_bloqueado'; }
else if (msgDemasiadoLargo) { bloqueado = true; motivoBloqueo = 'mensaje_excesivo'; }

const respuestasBloqueo = {
  dominio_baneado:    'Lo siento, no puedo procesar mensajes con ese tipo de enlaces.',
  contenido_bloqueado:'Por favor, mantén un tono respetuoso para que pueda ayudarte.',
  mensaje_excesivo:   'El mensaje es demasiado largo. ¿Puedes resumir tu consulta en pocas frases?'
};

return [{ json: { ...$json, clientId, client_id: clientId, companyName, company_name: companyName, sessionId, userMsg, bloqueado, motivoBloqueo, respuestaBloqueo: bloqueado ? (respuestasBloqueo[motivoBloqueo] || 'Mensaje no permitido.') : null } }];

const raw = $json || {};
const query = raw.query || {};
const body = raw.body || {};
const metadata = raw.metadata || {};

// Fallback para el iframe de demo. n8n Chat Trigger no siempre conserva query params
// entre la carga del iframe y el mensaje enviado al workflow.
const DEFAULT_CLIENT_ID = 'e3cf4d5e-a16d-4b64-8751-c7444c60ad26';
const DEFAULT_COMPANY_NAME = 'Empresa de Prueba';

const rawSessionId = raw.sessionId || body.sessionId || query.sessionId || $execution?.id || 'default';
const userMsg = (
  raw.chatInput ||
  raw.message ||
  raw.text ||
  body.chatInput ||
  body.message ||
  ''
).trim();

const clientId = String(
  raw.client_id ||
  raw.clientId ||
  body.client_id ||
  body.clientId ||
  query.client_id ||
  query.clientId ||
  metadata.client_id ||
  DEFAULT_CLIENT_ID
).trim();

const companyName = String(
  raw.company_name ||
  raw.companyName ||
  raw.empresa ||
  body.company_name ||
  body.companyName ||
  query.company_name ||
  query.companyName ||
  metadata.company_name ||
  DEFAULT_COMPANY_NAME
).trim();

if (!clientId) throw new Error('client_id es obligatorio para aislar el chatbot por cliente');

const sessionId = `${clientId}:${rawSessionId}`;

return [{ json: { ...raw, sessionId, rawSessionId, userMsg, clientId, client_id: clientId, companyName, company_name: companyName } }];

// ── Token y workspace desde Login ──────────────────────────
const loginJson   = $('Login').first().json;
const token       = loginJson.data.token;
const workspaceId = loginJson.data.user.active_workspace;

// ── Pipeline ID: primer pipeline de la lista ───────────────
const pipelineId  = $input.first().json.data[0].id;

// ── Datos del lead ──────────────────────────────────────────
const lead = $('Preparar Body API1').first().json.lead;

// ── follow_up_date: hoy en formato YYYY-MM-DD ───────────────
const d = new Date();
const followUpDate = d.toISOString().split('T')[0];

const body = {
  workspace_id:   workspaceId,
  pipeline_id:    pipelineId,
  name:           lead.nombre   || '',
  email:          lead.email    || '',
  subject:        lead.contexto || ('Lead chatbot: ' + (lead.producto_interes || 'General')),
  phone:          lead.telefono || '',
  follow_up_date: followUpDate
};

return [{ json: { token, body, bodyString: JSON.stringify(body) } }];
